const names = Object.keys(ICONS);
await mkdir(OUT_DIR, { recursive: true });
let written = 0;
for (const name of names) {
  const file = join(OUT_DIR, name + '.svg');
  await writeFile(file, ICONS[name], 'utf8');
  written++;
}
console.log('✓ wrote ' + written + ' icons to src/svg/');
